// ============================================================
// i18n — 多言語対応ランタイム
//
// theme.js の T / updateT と同じ「モジュールレベル singleton」方式。
// コンポーネントは t("key") を直接呼ぶだけでよく、Context 配線は不要。
// App.jsx が langPref state を持ち、毎レンダーで setLang() を呼ぶことで
// 言語変更時にツリー全体が再レンダーされ、t() が新しい言語を返す。
// ============================================================

// 対応言語（言語切替UIはこの配列を使う）
export const LANGUAGES = [
  { id: "ja", name: "日本語",  flag: "🇯🇵" },
  { id: "en", name: "English", flag: "🇺🇸" },
  { id: "zh", name: "简体中文", flag: "🇨🇳" },
  { id: "ko", name: "한국어",   flag: "🇰🇷" },
  { id: "tp", name: "toki pona", flag: "🟦" },
];

const SUPPORTED = new Set(LANGUAGES.map(l => l.id));
const FALLBACK = "ja";

// 現在の言語（singleton）
export let lang = FALLBACK;

export const getLang = () => lang;

// ブラウザ言語から初期値を推定（localStorage に保存が無い初回用）
export const detectLang = () => {
  try {
    const navs = (navigator.languages && navigator.languages.length)
      ? navigator.languages : [navigator.language || ""];
    for (const raw of navs) {
      const low = String(raw).toLowerCase();
      if (low.startsWith("ja")) return "ja";
      if (low.startsWith("zh")) return "zh";
      if (low.startsWith("ko")) return "ko";
      if (low.startsWith("en")) return "en";
    }
  } catch {}
  return FALLBACK;
};

export const setLang = (l) => {
  lang = SUPPORTED.has(l) ? l : FALLBACK;
};

