// 翻訳取得。t("key", { name: "x" }) で {name} を置換。
export const t = (key, vars) => {
  const entry = M[key];
  let s = entry ? (entry[lang] ?? entry[FALLBACK]) : key;
  if (s == null) s = key;
  if (vars) {
    for (const k in vars) s = s.split(`{${k}}`).join(String(vars[k]));
  }
  return s;
};

// サーバーが生成した日本語通知テキストを、既知パターンに一致させて
// 現在の言語で再描画する(バックエンド非改修のアプリ内シム)。
// 動的部分(ユーザー名・本文・科目名など)はそのまま保持。未知の形式や
// ユーザー生成内容はそのまま返す。lang==="ja" のときは原文と一致する。
export const formatNotif = (text) => {
  if (!text) return text;
  let m;
  if ((m = /^(.+)さんから友達申請が届きました$/.exec(text))) return t("notif.friendRequest", { name: m[1] });
  if ((m = /^(.+)さんがフレンド申請を承認しました$/.exec(text))) return t("notif.friendAccepted", { name: m[1] });
  if ((m = /^(.+)さんからメッセージ: ([\s\S]*)$/.exec(text))) {
    const pv = m[2] === "スタンプを送信しました" ? t("notif.sentStamp") : m[2];
    return t("notif.dmMessage", { name: m[1], preview: pv });
  }
  if ((m = /^(.+)さんが([\s\S]+)であなたをメンションしました$/.exec(text))) return t("notif.mention", { name: m[1], context: m[2] });
  if ((m = /^「([\s\S]+)」の提出期限が(.+)です$/.exec(text))) return t("notif.deadline", { title: m[1], label: m[2] });
  return text;
};

// 学院・学系オブジェクト(または名前文字列)を現在言語の名称で表示する。
// 派生オブジェクトでも .name さえあれば動く(JP名をキーに引く)。未登録は原文。
export const locName = (objOrName) => {
  const n = typeof objOrName === "string" ? objOrName : objOrName?.name;
  if (!n) return n ?? "";
  return M["sname." + n] ? t("sname." + n) : n;
};

// 学年暦ラベル(行事・祝日・試験・期間など)を JP 文字列キーで現在言語に。未登録は原文。
export const locCal = (s) => {
  if (!s) return s ?? "";
  return M["acal." + s] ? t("acal." + s) : s;
};

export default t;
